import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

const Tasks = () => {
  const { id: projectId } = useParams();
  const [tasks, setTasks] = useState([]);
  const [members, setMembers] = useState([]);
  const [form, setForm] = useState({
    title: '', description: '', dueDate: '', priority: 'medium', assignedTo: '',
  });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [progressEdit, setProgressEdit] = useState({}); // taskId → {progress, note}
  const { user } = useAuth();

  useEffect(() => {
    fetchTasks();
    if (user?.role === 'admin') fetchMembers();
  }, []);

  const fetchTasks = async () => {
    try {
      const { data } = await API.get(`/tasks?project=${projectId}`);
      setTasks(data.tasks);
      // Init progress edit state
      const init = {};
      data.tasks.forEach(t => {
        init[t._id] = { progress: t.progress || 0, note: t.progressNote || '' };
      });
      setProgressEdit(init);
    } catch (err) {
      setError('Failed to load tasks');
    }
  };

  const fetchMembers = async () => {
    try {
      const { data } = await API.get('/auth/users');
      setMembers(data.users);
    } catch (err) {
      console.error('Could not load members');
    }
  };

  const handleCreate = async () => {
    if (!form.title) return setError('Task title is required');
    setError('');
    try {
      await API.post('/tasks', { ...form, project: projectId });
      setForm({ title: '', description: '', dueDate: '', priority: 'medium', assignedTo: '' });
      setSuccess('Task created!');
      setTimeout(() => setSuccess(''), 3000);
      fetchTasks();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create task');
    }
  };

  const handleStatusChange = async (taskId, newStatus) => {
    try {
      // Auto set progress to 100 if done
      const updates = { status: newStatus };
      if (newStatus === 'done') updates.progress = 100;
      if (newStatus === 'todo') updates.progress = 0;
      await API.put(`/tasks/${taskId}`, updates);
      fetchTasks();
    } catch (err) {
      setError('Failed to update status');
    }
  };

  const handleAssignChange = async (taskId, newAssignee) => {
    try {
      await API.put(`/tasks/${taskId}`, { assignedTo: newAssignee });
      fetchTasks();
    } catch (err) {
      setError('Failed to reassign task');
    }
  };

  const handleProgressUpdate = async (taskId) => {
    try {
      const { progress, note } = progressEdit[taskId];
      const updates = { progress: Number(progress), progressNote: note };
      // Auto update status based on progress
      if (Number(progress) === 100) updates.status = 'done';
      else if (Number(progress) > 0) updates.status = 'in-progress';
      else updates.status = 'todo';
      await API.put(`/tasks/${taskId}`, updates);
      setSuccess('Progress updated!');
      setTimeout(() => setSuccess(''), 2000);
      fetchTasks();
    } catch (err) {
      setError('Failed to update progress');
    }
  };

  const handleDelete = async (taskId) => {
    if (!window.confirm('Delete this task?')) return;
    try {
      await API.delete(`/tasks/${taskId}`);
      fetchTasks();
    } catch (err) {
      setError('Failed to delete task');
    }
  };

  const unassigned = tasks.filter(t => !t.assignedTo).length;
  const done = tasks.filter(t => t.status === 'done').length;
  const inProgress = tasks.filter(t => t.status === 'in-progress').length;
  const avgProgress = tasks.length > 0
    ? Math.round(tasks.reduce((sum, t) => sum + (t.progress || 0), 0) / tasks.length)
    : 0;

  return (
    <div style={styles.container}>
      <h2 style={styles.heading}>✅ Tasks</h2>

      {error && <div style={styles.error}>{error}</div>}
      {success && <div style={styles.success}>{success}</div>}

      {/* Summary bar */}
      <div style={styles.summaryBar}>
        <div style={styles.summaryItem}>
          <span style={styles.summaryNum}>{tasks.length}</span>
          <span style={styles.summaryLabel}>Total</span>
        </div>
        <div style={styles.summaryItem}>
          <span style={{ ...styles.summaryNum, color: '#f59e0b' }}>{unassigned}</span>
          <span style={styles.summaryLabel}>Unassigned</span>
        </div>
        <div style={styles.summaryItem}>
          <span style={{ ...styles.summaryNum, color: '#8b5cf6' }}>{inProgress}</span>
          <span style={styles.summaryLabel}>In Progress</span>
        </div>
        <div style={styles.summaryItem}>
          <span style={{ ...styles.summaryNum, color: '#10b981' }}>{done}</span>
          <span style={styles.summaryLabel}>Done</span>
        </div>
        <div style={styles.summaryItem}>
          <span style={{ ...styles.summaryNum, color: '#6366f1' }}>{avgProgress}%</span>
          <span style={styles.summaryLabel}>Avg Progress</span>
        </div>
      </div>

      {/* Overall progress bar */}
      <div style={styles.overallBar}>
        <div style={styles.overallLabel}>
          <span>Overall Project Progress</span>
          <strong>{avgProgress}%</strong>
        </div>
        <div style={styles.progressTrack}>
          <div style={{
            ...styles.progressFill,
            width: `${avgProgress}%`,
            background: avgProgress === 100 ? '#10b981' : '#6366f1',
          }} />
        </div>
      </div>

      {/* Admin: Create task form */}
      {user?.role === 'admin' && (
        <div style={styles.form}>
          <h3 style={styles.formTitle}>➕ Add New Task</h3>
          <div style={styles.formGrid}>
            <input style={styles.input} placeholder="Task Title *"
              value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} />
            <input style={styles.input} placeholder="Description"
              value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} />
            <input style={styles.input} type="date"
              value={form.dueDate} onChange={e => setForm({ ...form, dueDate: e.target.value })} />
            <select style={styles.input} value={form.priority}
              onChange={e => setForm({ ...form, priority: e.target.value })}>
              <option value="low">🟢 Low Priority</option>
              <option value="medium">🟡 Medium Priority</option>
              <option value="high">🔴 High Priority</option>
            </select>
            <select style={styles.input} value={form.assignedTo}
              onChange={e => setForm({ ...form, assignedTo: e.target.value })}>
              <option value="">👤 Assign to member (optional)</option>
              {members.map(m => (
                <option key={m._id} value={m._id}>{m.name} ({m.role})</option>
              ))}
            </select>
          </div>
          <button style={styles.createBtn} onClick={handleCreate}>+ Create Task</button>
        </div>
      )}

      {/* Task list */}
      <div style={styles.list}>
        {tasks.map(task => {
          const isOver = task.dueDate &&
            new Date(task.dueDate) < new Date() && task.status !== 'done';
          const prog = progressEdit[task._id] || { progress: 0, note: '' };
          const isMyTask = task.assignedTo?._id === user?._id ||
            task.assignedTo === user?._id;
          const canEditProgress = user?.role === 'admin' || isMyTask;

          return (
            <div key={task._id} style={{
              ...styles.card,
              borderLeft: `4px solid ${
                isOver ? '#ef4444' :
                task.priority === 'high' ? '#ef4444' :
                task.priority === 'medium' ? '#f59e0b' : '#10b981'
              }`,
            }}>
              {/* Task header */}
              <div style={styles.cardHeader}>
                <div style={{ flex: 1 }}>
                  <h3 style={styles.cardTitle}>{task.title}</h3>
                  {task.description && <p style={styles.desc}>{task.description}</p>}
                </div>
                <div style={styles.cardRight}>
                  <span style={{
                    ...styles.priorityBadge,
                    background: task.priority === 'high' ? '#fee2e2' :
                      task.priority === 'medium' ? '#fef3c7' : '#dcfce7',
                    color: task.priority === 'high' ? '#dc2626' :
                      task.priority === 'medium' ? '#d97706' : '#16a34a',
                  }}>
                    {task.priority}
                  </span>
                  {user?.role === 'admin' && (
                    <button style={styles.deleteBtn} onClick={() => handleDelete(task._id)}>🗑️</button>
                  )}
                </div>
              </div>

              {/* Due date */}
              {task.dueDate && (
                <p style={{ ...styles.due, color: isOver ? '#ef4444' : '#f59e0b' }}>
                  📅 {new Date(task.dueDate).toLocaleDateString()}
                  {isOver ? ' ⚠️ Overdue!' : ''}
                </p>
              )}

              {/* ── PROGRESS SECTION ─────────────────── */}
              <div style={styles.progressSection}>
                <div style={styles.progressHeader}>
                  <span style={styles.progressLabel}>📊 Progress</span>
                  <span style={{
                    ...styles.progressPct,
                    color: task.progress === 100 ? '#10b981' : '#6366f1',
                  }}>
                    {task.progress || 0}%
                  </span>
                </div>

                {/* Progress bar */}
                <div style={styles.progressTrack}>
                  <div style={{
                    ...styles.progressFill,
                    width: `${task.progress || 0}%`,
                    background: task.progress === 100 ? '#10b981' :
                      task.progress > 50 ? '#6366f1' : '#f59e0b',
                  }} />
                </div>

                {/* Editable progress (member assigned or admin) */}
                {canEditProgress && (
                  <div style={styles.progressEdit}>
                    <div style={styles.sliderRow}>
                      <span style={styles.sliderLabel}>Update:</span>
                      <input
                        type="range" min="0" max="100" step="5"
                        value={prog.progress}
                        onChange={e => setProgressEdit({
                          ...progressEdit,
                          [task._id]: { ...prog, progress: e.target.value }
                        })}
                        style={styles.slider}
                      />
                      <span style={styles.sliderVal}>{prog.progress}%</span>
                    </div>
                    <input
                      style={styles.noteInput}
                      placeholder="Add a progress note (optional)..."
                      value={prog.note}
                      onChange={e => setProgressEdit({
                        ...progressEdit,
                        [task._id]: { ...prog, note: e.target.value }
                      })}
                    />
                    <button style={styles.updateBtn}
                      onClick={() => handleProgressUpdate(task._id)}>
                      💾 Save Progress
                    </button>
                  </div>
                )}

                {/* Show existing note */}
                {task.progressNote && !canEditProgress && (
                  <div style={styles.noteDisplay}>
                    💬 {task.progressNote}
                  </div>
                )}
                {task.progressNote && canEditProgress && (
                  <div style={styles.noteDisplay}>
                    💬 Last note: {task.progressNote}
                  </div>
                )}
              </div>

              {/* Assign row (admin) */}
              <div style={styles.metaRow}>
                <span style={styles.metaLabel}>👤 Assigned to:</span>
                {user?.role === 'admin' ? (
                  <select style={styles.metaSelect}
                    value={task.assignedTo?._id || ''}
                    onChange={e => handleAssignChange(task._id, e.target.value)}>
                    <option value="">— Unassigned —</option>
                    {members.map(m => (
                      <option key={m._id} value={m._id}>{m.name} ({m.role})</option>
                    ))}
                  </select>
                ) : (
                  <span style={styles.metaVal}>
                    {task.assignedTo?.name || 'Unassigned'}
                  </span>
                )}
              </div>

              {/* Status row */}
              <div style={styles.metaRow}>
                <span style={styles.metaLabel}>📌 Status:</span>
                <select style={styles.metaSelect}
                  value={task.status}
                  onChange={e => handleStatusChange(task._id, e.target.value)}
                  disabled={user?.role === 'member' && !isMyTask}>
                  <option value="todo">📋 To Do</option>
                  <option value="in-progress">⚙️ In Progress</option>
                  <option value="done">✅ Done</option>
                </select>
              </div>
            </div>
          );
        })}
      </div>

      {tasks.length === 0 && (
        <div style={styles.emptyBox}>
          <p style={{ fontSize: '36px', margin: '0 0 8px' }}>📭</p>
          <p style={{ color: '#94a3b8', margin: 0 }}>
            {user?.role === 'admin'
              ? 'No tasks yet. Add one above!'
              : 'No tasks assigned to you in this project.'}
          </p>
        </div>
      )}
    </div>
  );
};

const styles = {
  container: { maxWidth: '900px', margin: '0 auto', paddingBottom: '40px' },
  heading: { color: '#0f172a', marginBottom: '20px' },
  error: { background: '#fee2e2', color: '#dc2626', padding: '12px', borderRadius: '8px', marginBottom: '16px' },
  success: { background: '#dcfce7', color: '#16a34a', padding: '12px', borderRadius: '8px', marginBottom: '16px' },
  summaryBar: {
    display: 'flex', gap: '12px', marginBottom: '20px',
    background: '#0f172a', borderRadius: '14px', padding: '16px 24px',
    flexWrap: 'wrap',
  },
  summaryItem: { textAlign: 'center', flex: 1, minWidth: '80px' },
  summaryNum: { display: 'block', fontSize: '26px', fontWeight: '800', color: 'white' },
  summaryLabel: { fontSize: '11px', color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.5px' },
  overallBar: {
    background: 'white', borderRadius: '12px', padding: '16px 20px',
    marginBottom: '24px', boxShadow: '0 2px 8px rgba(0,0,0,0.06)',
  },
  overallLabel: {
    display: 'flex', justifyContent: 'space-between',
    fontSize: '14px', color: '#64748b', marginBottom: '8px',
  },
  progressTrack: {
    height: '10px', background: '#f1f5f9', borderRadius: '5px', overflow: 'hidden',
  },
  progressFill: { height: '100%', borderRadius: '5px', transition: 'width 0.5s ease' },
  form: {
    background: 'white', padding: '24px', borderRadius: '14px',
    boxShadow: '0 2px 12px rgba(0,0,0,0.07)', marginBottom: '24px',
  },
  formTitle: { margin: '0 0 16px', color: '#0f172a' },
  formGrid: { display: 'flex', flexDirection: 'column', gap: '10px', marginBottom: '14px' },
  input: { padding: '10px 14px', border: '1px solid #e2e8f0', borderRadius: '8px', fontSize: '14px' },
  createBtn: {
    background: '#6366f1', color: 'white', border: 'none',
    padding: '12px', borderRadius: '8px', cursor: 'pointer',
    fontWeight: '700', width: '100%', fontSize: '15px',
  },
  list: { display: 'flex', flexDirection: 'column', gap: '16px' },
  card: {
    background: 'white', padding: '20px', borderRadius: '14px',
    boxShadow: '0 2px 10px rgba(0,0,0,0.07)',
  },
